using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

namespace TicketClassifier.Models;

public class TicketResponse
{
    public required string Category { get; set; }
    public required Dictionary<string, float> Confidence { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains the ticket classification model at startup and logs evaluation metrics.
/// </summary>
public class ModelTrainerService(ILogger<ModelTrainerService> logger) : IHostedService
{
    public const string ModelPath = "Data/model.zip";
    private static readonly string[] CategoryLabels = ["Billing", "General", "Technical"];

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        var csvPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            csvPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        logger.LogInformation("===== Model Evaluation Metrics =====");
        logger.LogInformation("Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        logger.LogInformation("Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        logger.LogInformation("Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        logger.LogInformation("Log Loss Reduction: {LogLossReduction:F4}", metrics.LogLossReduction);

        for (var i = 0; i < CategoryLabels.Length; i++)
        {
            if (i < metrics.PerClassLogLoss.Count)
            {
                logger.LogInformation("  {Category} Log Loss: {Loss:F4}",
                    CategoryLabels[i], metrics.PerClassLogLoss[i]);
            }
        }

        var modelFullPath = Path.Combine(AppContext.BaseDirectory, ModelPath);
        mlContext.Model.Save(model, data.Schema, modelFullPath);
        logger.LogInformation("Model saved to {Path}", modelFullPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool) : ControllerBase
{
    private static readonly string[] Labels = ["Billing", "General", "Technical"];

    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < Labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[Labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            Category = prediction.Category,
            Confidence = confidence
        });
    }
}

